import Foundation
import Darwin

public actor UsagesFileManager {
    // Internal init so tests can create isolated instances via @testable import.
    // Production code must use `UsagesFileManager.shared`.
    public static let shared = UsagesFileManager()

    nonisolated public let filePath: String
    nonisolated public let lockPath: String
    private let logger: FileLogger
    private let lockTimeoutSeconds: TimeInterval

    init(
        filePath: String? = nil,
        logger: FileLogger = Loggers.app,
        lockTimeoutSeconds: TimeInterval = 5.0
    ) {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        self.filePath = filePath ?? "\(home)/.cache/ai-usages-tracker/usages.json"
        self.logger = logger
        self.lockPath = self.filePath + ".lock"
        self.lockTimeoutSeconds = lockTimeoutSeconds

        let dir = (self.filePath as NSString).deletingLastPathComponent
        do {
            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
        } catch {
            logger.log(.error, "Failed to create directory \(dir): \(error)")
        }
    }

    // MARK: - Public

    public func read() async -> UsagesFile {
        do {
            return try await withFileLock(mode: LOCK_SH) { readUnsafe() }
        } catch is CancellationError {
            return UsagesFile()
        } catch {
            logger.log(.warning, "flock read failed — returning empty file: \(error)")
            return UsagesFile()
        }
    }

    public func update(with entries: [VendorUsageEntry]) async {
        do {
            try await withFileLock(mode: LOCK_EX) {
                var file = readUnsafe()
                file = merge(existing: file, incoming: entries)
                writeUnsafe(file)
            }
        } catch is CancellationError {
            return
        } catch {
            logger.log(.warning, "flock update failed — skipping write: \(error)")
        }
    }

    // MARK: - Active-account update

    public func updateIsActive(vendor: Vendor, activeAccount: AccountEmail?) async {
        do {
            try await withFileLock(mode: LOCK_EX) {
                var file = readUnsafe()
                var changed = false
                for i in file.usages.indices {
                    guard file.usages[i].vendor == vendor else { continue }
                    let newActive = file.usages[i].account == activeAccount
                    if file.usages[i].isActive != newActive {
                        file.usages[i].isActive = newActive
                        changed = true
                    }
                }
                if changed {
                    writeUnsafe(file)
                }
            }
        } catch is CancellationError {
            return
        } catch {
            logger.log(.warning, "flock updateIsActive failed — skipping: \(error)")
        }
    }

    // MARK: - Merge logic

    func merge(existing: UsagesFile, incoming: [VendorUsageEntry]) -> UsagesFile {
        var usages = existing.usages
        var indexByKey: [String: Int] = [:]
        for (i, entry) in usages.enumerated() {
            indexByKey["\(entry.vendor.rawValue)|\(entry.account.rawValue)"] = i
        }
        for entry in incoming {
            let key = "\(entry.vendor.rawValue)|\(entry.account.rawValue)"
            if let idx = indexByKey[key] {
                if entry.lastError != nil {
                    // Errors must not erase previously acquired data: the file may hold good
                    // metrics from a prior successful fetch while the connector's in-memory
                    // lastKnownMetrics is empty (e.g. after an app restart).
                    var merged = entry
                    if merged.metrics.isEmpty {
                        merged.metrics = usages[idx].metrics
                    }
                    if merged.lastAcquiredOn == nil {
                        merged.lastAcquiredOn = usages[idx].lastAcquiredOn
                    }
                    usages[idx] = merged
                } else {
                    usages[idx] = entry
                }
            } else {
                indexByKey[key] = usages.count
                usages.append(entry)
            }
        }
        // When a vendor fetch succeeds, discard stale error entries that won't be replaced
        // (e.g. the "unknown" placeholder written while resolveActiveAccount() temporarily failed).
        let incomingKeys = Set(incoming.map { "\($0.vendor.rawValue)|\($0.account.rawValue)" })
        let vendorsWithSuccess = Set(incoming.filter { $0.lastError == nil }.map { $0.vendor })
        if !vendorsWithSuccess.isEmpty {
            usages = usages.filter { entry in
                let key = "\(entry.vendor.rawValue)|\(entry.account.rawValue)"
                return !vendorsWithSuccess.contains(entry.vendor)
                    || incomingKeys.contains(key)
                    || entry.lastError == nil
            }
        }
        return UsagesFile(usages: usages)
    }

    // MARK: - Lock-guarded internals

    /// Acquires an advisory flock on the dedicated lock file, runs `body`, then releases.
    /// Uses a separate lock file because atomic writes replace the JSON inode, making
    /// flock on the data file itself ineffective for protecting external readers.
    private func withFileLock<T>(mode: Int32, body: () throws -> T) async throws -> T {
        let fd = Darwin.open(lockPath, O_CREAT | O_RDWR, 0o644)
        guard fd >= 0 else { throw FileManagerError.cannotOpenLockFile(path: lockPath) }
        defer { Darwin.close(fd) }

        let deadline = Date().addingTimeInterval(lockTimeoutSeconds)
        while flock(fd, mode | LOCK_NB) != 0 {
            guard Date() < deadline else {
                throw FileManagerError.lockTimeout(path: lockPath, timeoutSeconds: lockTimeoutSeconds)
            }
            try await Task.sleep(for: .milliseconds(50))
        }
        defer { flock(fd, LOCK_UN) }

        return try body()
    }

    // MARK: - Unsafe (actor-isolated, no external lock needed)

    private func readUnsafe() -> UsagesFile {
        guard let data = FileManager.default.contents(atPath: filePath) else {
            return UsagesFile()
        }
        do {
            return try JSONDecoder().decode(UsagesFile.self, from: data)
        } catch {
            logger.log(.error, "Failed to decode \(filePath): \(error)")
            return UsagesFile()
        }
    }

    private func writeUnsafe(_ file: UsagesFile) {
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
        guard let data = try? encoder.encode(file) else {
            logger.log(.error, "Failed to encode usages file")
            return
        }
        do {
            try data.write(to: URL(fileURLWithPath: filePath), options: .atomic)
        } catch {
            logger.log(.error, "Atomic write failed: \(error)")
            return
        }
        logger.log(.debug, "Wrote usages file to \(filePath)")
    }
}

enum FileManagerError: Error, CustomStringConvertible {
    case cannotOpenLockFile(path: String)
    case lockTimeout(path: String, timeoutSeconds: Double)

    var description: String {
        switch self {
        case let .cannotOpenLockFile(path):
            "Cannot open lock file at \(path)"
        case let .lockTimeout(path, secs):
            "Could not acquire flock on \(path) within \(secs)s"
        }
    }
}

import Foundation
import Observation

// MARK: - Clock abstraction (testable time source)

/// Abstracts `Date.now` so tests can inject a fixed point in time.
public protocol ClockProvider: Sendable {
    func now() -> Date
}

public struct SystemClock: ClockProvider {
    public init() {}
    public func now() -> Date { Date() }
}

// MARK: - Store

/// One segment of the menu bar label — a single metric's formatted text and its tier.
public struct MenuBarSegment: Sendable {
    public let text: String
    public let tier: ConsumptionTier?
}

/// Formats the active Claude account's time-window metrics for the menu bar.
/// Example: `S 48% 2h 13m | W 7% 6d 6h 13m`. Falls back to `"--"` when data is
/// unavailable, malformed, or no active account is found.
@Observable
@MainActor
public final class UsageStore {
    public private(set) var menuBarText: String = "--"
    public private(set) var menuBarTier: ConsumptionTier?
    public private(set) var menuBarSegments: [MenuBarSegment] = []
    /// Incremented each time handleNewData is called, whether the data is valid or malformed.
    /// Tests use this as a reliable signal that the store has consumed the latest yielded item.
    public private(set) var dataProcessedCount: Int = 0
    public private(set) var entries: [VendorUsageEntry] = []

    // MARK: Dependencies

    private let fileWatcher: FileWatching
    private let clock: ClockProvider
    private let logger: FileLogger
    private let countdownRefreshSeconds: UInt64

    public static let defaultCountdownRefreshSeconds: UInt64 = 60
    private static let fallbackText = "--"
    private static let targetVendor: Vendor = .claude
    // Only top-level aggregate metrics belong in the compact menu bar label; per-model breakdowns live in the popover only
    private static let menuBarMetricNames: Set<String> = ["session", "weekly"]

    // Latest decoded file kept for countdown refresh without re-reading disk
    private var lastFile: UsagesFile?

    private var watchTask: Task<Void, Never>?
    private var countdownTask: Task<Void, Never>?

    public init(
        fileWatcher: FileWatching,
        clock: ClockProvider = SystemClock(),
        logger: FileLogger = Loggers.app,
        countdownRefreshSeconds: UInt64 = UsageStore.defaultCountdownRefreshSeconds
    ) {
        self.fileWatcher = fileWatcher
        self.clock = clock
        self.logger = logger
        self.countdownRefreshSeconds = countdownRefreshSeconds
    }

    // MARK: Lifecycle

    /// Start watching the file and refreshing the countdown.
    /// Idempotent — calling again is a no-op.
    public func start() {
        guard watchTask == nil else { return }

        let watcher = fileWatcher
        // Self is captured strongly; stop() cancels both tasks to break the cycle
        watchTask = Task { [self] in
            for await data in watcher.changes() {
                guard !Task.isCancelled else { break }
                self.handleNewData(data)
            }
        }

        countdownTask = Task { [self] in
            let refreshNanos = self.countdownRefreshSeconds * 1_000_000_000
            while !Task.isCancelled {
                // CancellationError swallowed intentionally; checked on next loop iteration
                try? await Task.sleep(nanoseconds: refreshNanos)
                guard !Task.isCancelled else { break }
                self.refreshMenuBarText()
            }
        }
    }

    /// Stop all background tasks. Idempotent.
    public func stop() {
        watchTask?.cancel()
        watchTask = nil
        countdownTask?.cancel()
        countdownTask = nil
    }

    // Defensive: cancels tasks when the store is released without an explicit stop() call.
    @MainActor deinit { stop() }

    // MARK: - Processing

    private func handleNewData(_ data: Data) {
        dataProcessedCount += 1
        do {
            let file = try JSONDecoder().decode(UsagesFile.self, from: data)
            lastFile = file
            entries = file.usages
            let result = format(file: file)
            menuBarText = result.text
            menuBarTier = result.tier
            menuBarSegments = result.segments
        } catch {
            logger.log(.error, "UsageStore: JSON decode failed: \(error)")
            lastFile = nil
            entries = []
            menuBarText = Self.fallbackText
            menuBarTier = nil
            menuBarSegments = []
        }
    }

    private func refreshMenuBarText() {
        guard let file = lastFile else { return }
        let result = format(file: file)
        menuBarText = result.text
        menuBarTier = result.tier
        menuBarSegments = result.segments
    }

    // MARK: - Formatting

    private struct FormatResult {
        let segments: [MenuBarSegment]
        let text: String
        let tier: ConsumptionTier?
    }

    private func format(file: UsagesFile) -> FormatResult {
        guard let entry = file.usages.first(where: {
            $0.vendor == Self.targetVendor && $0.isActive
        }) else {
            return FormatResult(segments: [], text: Self.fallbackText, tier: nil)
        }

        let now = clock.now()
        var segments: [MenuBarSegment] = []

        for metric in entry.metrics {
            guard let segment = formatTimeWindowSegment(metric, now: now) else { continue }
            segments.append(segment)
        }

        let worstTier = segments.compactMap(\.tier).max()
        let text = segments.isEmpty ? Self.fallbackText : segments.map(\.text).joined(separator: " | ")
        return FormatResult(segments: segments, text: text, tier: segments.isEmpty ? nil : worstTier)
    }

    private func formatTimeWindowSegment(_ metric: UsageMetric, now: Date) -> MenuBarSegment? {
        if case let .unknown(t) = metric {
            logger.log(.debug, "UsageStore: skipping unknown metric type '\(t)'")
        }
        guard case let .timeWindow(name, resetAt, windowDuration, usagePercent) = metric else {
            return nil
        }
        guard Self.menuBarMetricNames.contains(name) else { return nil }

        let abbreviation = name.prefix(1).uppercased()
        // A metric with an empty name cannot be abbreviated — skip to avoid a leading space in output
        guard !abbreviation.isEmpty else { return nil }

        let remaining = formatRemainingTime(resetAt: resetAt, now: now)
        let text = "\(abbreviation) \(usagePercent.rawValue)% \(remaining)"

        let theoretical = theoreticalFraction(resetAt: resetAt, windowDuration: windowDuration, now: now)
        let tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: theoretical)
            .map { consumptionTier(ratio: $0) }

        return MenuBarSegment(text: text, tier: tier)
    }

    private func formatRemainingTime(resetAt: ISODate, now: Date) -> String {
        guard resetAt.date != nil else {
            logger.log(.warning, "UsageStore: invalid ISO8601 resetAt value: \(resetAt.rawValue)")
            return "--"
        }
        return AIUsagesTrackersLib.formatRemainingTime(resetAt: resetAt, now: now)
    }
}

